// App.jsx — Spandan Patil portfolio v3 (cockpit + hyperspace + themed tiles)
const TWEAK_DEFAULTS = /*EDITMODE-BEGIN*/{
  "stars": "heavy",
  "curve": true,
  "accent": "#6CE7C9"
}/*EDITMODE-END*/;

const PORTRAIT = "data:image/jpeg;base64,";

const PROJECTS_AT = {
  7:  { n:'01', title:'Pit or Persist',         art:'art-f1' },
  8:  { n:'02', title:'Market Sentiment',       art:'art-stocks' },
  9:  { n:'03', title:'Splice Sense',           art:'art-dna' },
  10: { n:'04', title:'LLM Eval Harness',       art:'art-llm' },
  13: { n:'05', title:'BetGCN',                 art:'art-gnn' },
  14: { n:'06', title:'MMDS · Suspicious',      art:'art-social' },
  15: { n:'07', title:'Fashion · WIP',          art:'art-fashion' },
  16: { n:'08', title:'Artscii',                art:'art-ascii' },
};
const AMBIENT_ROTATION = ['art-mesh','art-orb','art-rings','art-stack','art-flame','art-grid','art-bars','art-wave','art-glyph-pi','art-net','art-mesh','art-orb','art-rings','art-stack','art-flame','art-grid'];

function fmtClock() {
  return new Intl.DateTimeFormat('en-US', { timeZone: 'America/New_York', hour: '2-digit', minute: '2-digit', hour12: false }).format(new Date()) + ' EST';
}

function ArtF1() {
  return (
    <div className="tile-art art-f1">
      <svg viewBox="0 0 200 250" preserveAspectRatio="none" className="art-svg">
        <ellipse cx="100" cy="180" rx="78" ry="14" fill="none" stroke="#FF6B5C" strokeOpacity=".25" strokeWidth="14"/>
        <ellipse cx="100" cy="180" rx="78" ry="14" fill="none" stroke="#fff" strokeOpacity=".15" strokeDasharray="3 6"/>
        <g className="f1-lines">
          {[0,1,2,3,4].map(i=>(
            <line key={i} x1={20+i*38} y1={60+i*8} x2={50+i*38} y2={60+i*8} stroke="#FF6B5C" strokeOpacity=".5" strokeWidth="1.5"/>
          ))}
        </g>
        <g className="f1-car">
          <rect x="78" y="170" width="44" height="8" rx="2" fill="#fff"/>
          <circle cx="84" cy="180" r="4" fill="#FF6B5C"/>
          <circle cx="116" cy="180" r="4" fill="#FF6B5C"/>
          <rect x="92" y="164" width="16" height="6" rx="1" fill="#FF6B5C"/>
          <polygon points="78,170 70,176 78,178" fill="#fff"/>
          <polygon points="122,170 130,176 122,178" fill="#fff"/>
        </g>
      </svg>
    </div>
  );
}

function ArtStocks() {
  return (
    <div className="tile-art art-stocks">
      <svg viewBox="0 0 200 250" preserveAspectRatio="none" className="art-svg">
        <defs>
          <linearGradient id="up" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0" stopColor="#6CE7C9" stopOpacity=".4"/>
            <stop offset="1" stopColor="#6CE7C9" stopOpacity="0"/>
          </linearGradient>
        </defs>
        {[60,100,140,180].map(y => <line key={y} x1="0" x2="200" y1={y} y2={y} stroke="#3A4258" strokeOpacity=".3"/>)}
        <path d="M 0,200 L 20,180 L 40,160 L 60,170 L 80,140 L 100,150 L 120,110 L 140,120 L 160,80 L 180,90 L 200,60 L 200,250 L 0,250 Z" fill="url(#up)"/>
        <polyline points="0,200 20,180 40,160 60,170 80,140 100,150 120,110 140,120 160,80 180,90 200,60" fill="none" stroke="#6CE7C9" strokeWidth="1.8" className="stocks-line"/>
        {[[40,135,165],[80,115,150],[120,90,130],[160,70,100]].map(([x,t,b],i)=>(
          <g key={i}>
            <line x1={x} x2={x} y1={t-8} y2={b+8} stroke="#6CE7C9"/>
            <rect x={x-3} y={t} width="6" height={b-t} fill={i%2?"#6CE7C9":"#0A0E18"} stroke="#6CE7C9"/>
          </g>
        ))}
      </svg>
    </div>
  );
}

function ArtDNA() {
  return (
    <div className="tile-art art-dna">
      <svg viewBox="0 0 200 250" preserveAspectRatio="xMidYMid slice" className="art-svg dna-rotate">
        {Array.from({length:14}).map((_,i)=>{
          const y = 20 + i*16;
          const phase = (i / 14) * Math.PI * 4;
          const x1 = 100 + Math.sin(phase) * 36;
          const x2 = 100 - Math.sin(phase) * 36;
          const front = Math.sin(phase) > 0;
          return (
            <g key={i} opacity={0.5 + Math.abs(Math.cos(phase))*0.5}>
              <line x1={x1} y1={y} x2={x2} y2={y} stroke={front ? "#6CE7C9" : "#B38CFF"} strokeOpacity=".5" strokeWidth="1"/>
              <circle cx={x1} cy={y} r="3" fill="#6CE7C9"/>
              <circle cx={x2} cy={y} r="3" fill="#B38CFF"/>
            </g>
          );
        })}
      </svg>
    </div>
  );
}

function ArtLLM() {
  const lines = [
    '> evaluate(reasoning)',
    '  loaded 412 tasks',
    '  scoring batch 1/8...',
    '  [████████░░] 80%',
    '  pass@1 = 0.74'
  ];
  return (
    <div className="tile-art art-llm">
      <pre className="llm-code">
        {lines.join('\n')}<span className="caret">▌</span>
      </pre>
    </div>
  );
}

function ArtGNN() {
  const nodes = [[100,40],[40,80],[160,80],[60,150],[140,150],[100,200],[30,200],[170,200]];
  const edges = [[0,1],[0,2],[1,3],[2,4],[3,5],[4,5],[1,4],[2,3],[3,6],[5,7],[4,7],[6,3]];
  return (
    <div className="tile-art art-gnn">
      <svg viewBox="0 0 200 250" preserveAspectRatio="xMidYMid slice" className="art-svg">
        <defs>
          <radialGradient id="gnn-glow"><stop offset="0" stopColor="#6CE7C9" stopOpacity=".5"/><stop offset="1" stopColor="#6CE7C9" stopOpacity="0"/></radialGradient>
        </defs>
        {edges.map(([a,b],i)=>(
          <line key={i} x1={nodes[a][0]} y1={nodes[a][1]} x2={nodes[b][0]} y2={nodes[b][1]} stroke="#6CE7C9" strokeOpacity=".35" strokeWidth=".8" className="gnn-edge" style={{animationDelay: (i*0.2)+'s'}}/>
        ))}
        {nodes.map((p,i)=>(
          <g key={i}>
            <circle cx={p[0]} cy={p[1]} r="10" fill="url(#gnn-glow)"/>
            <circle cx={p[0]} cy={p[1]} r="4" fill="#6CE7C9" className="gnn-node" style={{animationDelay: (i*0.3)+'s'}}/>
          </g>
        ))}
      </svg>
    </div>
  );
}

function ArtSocial() {
  const nodes = [
    [60,70],[40,100],[80,110],[60,140],[35,140],
    [140,80],[160,110],[130,110],[155,140],[120,140],
    [100,200],[70,210],[130,210]
  ];
  return (
    <div className="tile-art art-social">
      <svg viewBox="0 0 200 250" preserveAspectRatio="xMidYMid slice" className="art-svg">
        {[[0,1],[0,2],[1,3],[2,3],[1,4],[3,4],[0,3]].map(([a,b],i)=>(
          <line key={'a'+i} x1={nodes[a][0]} y1={nodes[a][1]} x2={nodes[b][0]} y2={nodes[b][1]} stroke="#3A4258" strokeWidth=".6"/>
        ))}
        {[[5,6],[5,7],[6,8],[7,8],[7,9],[8,9],[5,8]].map(([a,b],i)=>(
          <line key={'b'+i} x1={nodes[a][0]} y1={nodes[a][1]} x2={nodes[b][0]} y2={nodes[b][1]} stroke="#3A4258" strokeWidth=".6"/>
        ))}
        {[[10,3],[10,9],[10,11],[10,12],[11,3],[12,9]].map(([a,b],i)=>(
          <line key={'x'+i} x1={nodes[a][0]} y1={nodes[a][1]} x2={nodes[b][0]} y2={nodes[b][1]} stroke="#FF6B5C" strokeOpacity=".7" strokeWidth=".8" className="social-bridge"/>
        ))}
        {nodes.map((p,i)=>(
          <circle key={i} cx={p[0]} cy={p[1]} r={i===10?6:3} fill={i===10?"#FF6B5C":"#C7CDD9"} className={i===10?"social-bad":""}/>
        ))}
      </svg>
    </div>
  );
}

function ArtFashion() {
  return (
    <div className="tile-art art-fashion">
      <svg viewBox="0 0 200 250" preserveAspectRatio="xMidYMid slice" className="art-svg">
        <defs>
          <linearGradient id="fab" x1="0" y1="0" x2="1" y2="1">
            <stop offset="0" stopColor="#B38CFF"/><stop offset="1" stopColor="#FF6B5C"/>
          </linearGradient>
          <pattern id="weave" width="6" height="6" patternUnits="userSpaceOnUse">
            <rect width="3" height="3" fill="#1A2030"/>
            <rect x="3" y="3" width="3" height="3" fill="#1A2030"/>
          </pattern>
        </defs>
        <rect width="200" height="250" fill="url(#weave)"/>
        <path d="M 100,40 L 80,80 L 60,140 L 50,210 L 150,210 L 140,140 L 120,80 Z" fill="url(#fab)" fillOpacity=".75" stroke="#fff" strokeOpacity=".3"/>
        <circle cx="100" cy="32" r="6" fill="none" stroke="#F2C14E" strokeWidth="1.5"/>
        <line x1="100" y1="38" x2="100" y2="44" stroke="#F2C14E" strokeWidth="1.5"/>
        <path d="M 60,140 L 140,140" stroke="#F2C14E" strokeDasharray="2 3" strokeWidth=".8"/>
      </svg>
    </div>
  );
}

function ArtAscii() {
  const rows = [
    '    .,;okKXXKko;,..   ',
    '  .;dXMMMMMMMMMMMNd;. ',
    ' :OWMMMMMMMMMMMMMMMNk;',
    ':KMMMMMNk:.    .:dXMMM',
    'dWMMMNo.   ::    .KMMM',
    'oWMMMNl   :OXKx:  dWMM',
    'dMMMMNc  lXMMMMNl cNMM',
    'dMMMMNl   dWMMMW0 oWMM',
    ':NMMMNo    dXKx: lNMMM',
    ' oWMMMNd:    .:lkXMMMM'
  ];
  return (
    <div className="tile-art art-ascii">
      <pre className="ascii-pre">{rows.join('\n')}</pre>
    </div>
  );
}

function AmbientArt({ kind }) {
  if (kind === 'art-glyph-pi') return <div className="tile-art art-glyph" data-glyph="π"/>;
  if (kind === 'art-net') return (
    <div className="tile-art art-net">
      <svg viewBox="0 0 200 250" preserveAspectRatio="xMidYMid slice" className="art-svg">
        {[[40,80],[160,60],[100,140],[60,200],[170,180],[120,40],[30,150]].map((p,i)=>(
          <circle key={i} cx={p[0]} cy={p[1]} r="2" fill="#6CE7C9" opacity=".7"/>
        ))}
      </svg>
    </div>
  );
  return <div className={'tile-art ' + kind}/>;
}

function ProjectTile({ p, onOpen, idx }) {
  const ArtMap = { 'art-f1':ArtF1, 'art-stocks':ArtStocks, 'art-dna':ArtDNA, 'art-llm':ArtLLM, 'art-gnn':ArtGNN, 'art-social':ArtSocial, 'art-fashion':ArtFashion, 'art-ascii':ArtAscii };
  const Art = ArtMap[p.art];
  return (
    <a className="tile project" href="#" onClick={(e)=>{ e.preventDefault(); onOpen(p, idx); }}>
      <Art/>
      <div className="tile-num">{p.n}</div>
      <div className="tile-name">{p.title}</div>
      <div className="tile-view">↗ View</div>
    </a>
  );
}

function WorkPage({ onOpen }) {
  const cells = [];
  let ambIdx = 0;
  for (let i=0; i<24; i++) {
    const p = PROJECTS_AT[i];
    if (p) cells.push(<ProjectTile key={i} p={p} onOpen={onOpen} idx={i}/>);
    else cells.push(<AmbientArt key={i} kind={AMBIENT_ROTATION[ambIdx++ % AMBIENT_ROTATION.length]}/>);
  }
  return (
    <section className="cockpit">
      <div className="cockpit-perspective">
        <div className="cockpit-grid">
          {cells.map((c, i) => {
            const row = Math.floor(i/6), col = i%6;
            const dx = col - 2.5, dy = row - 1.5;
            const dist = Math.sqrt(dx*dx + dy*dy);
            return (
              <div key={i} className="cell" data-row={row} data-col={col}
                   style={{ '--dx': dx, '--dy': dy, '--dist': dist.toFixed(2) }}>
                {c}
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}

const CONTACTS = [
  { label:'Email',          glyph:'✉',  href:'#' },
  { label:'LinkedIn',       glyph:'in', href:'#' },
  { label:'GitHub',         glyph:'</>',href:'#' },
  { label:'Instagram',      glyph:'◫',  href:'#' },
  { label:'Google Scholar', glyph:'§',  href:'#' },
  { label:'Resume',         glyph:'↧',  href:'#' },
];

