function Hyperspace({ active }) {
  const streaks = React.useMemo(() => Array.from({length: 80}).map(() => ({
    a: Math.random() * Math.PI * 2,
    len: 30 + Math.random()*70,
    delay: Math.random()*0.3
  })), []);
  return (
    <div className={'hyperspace ' + (active?'go':'')}>
      <div className="hs-streaks">
        {streaks.map((s,i)=>(
          <span key={i} style={{ '--a': s.a + 'rad', '--len': s.len + 'px', '--delay': s.delay + 's' }}/>
        ))}
      </div>
      <div className="hs-flash"/>
    </div>
  );
}

function App() {
  const [t, setTweak] = useTweaks(TWEAK_DEFAULTS);
  const [page, setPage] = React.useState('work');
  const [toast, setToast] = React.useState('');
  const [clock, setClock] = React.useState(fmtClock());
  const [hyper, setHyper] = React.useState(false);

  React.useEffect(()=>{
    document.body.dataset.stars = t.stars;
    document.body.dataset.curve = String(t.curve);
    document.documentElement.style.setProperty('--signal', t.accent);
  }, [t.stars, t.curve, t.accent]);
  React.useEffect(()=>{ const i = setInterval(()=> setClock(fmtClock()), 30000); return ()=> clearInterval(i); }, []);

  const showToast = (msg) => { setToast(msg); setTimeout(()=> setToast(''), 1800); };

  const openProject = (p, idx) => {
    setHyper(true);
    setTimeout(()=>{
      showToast(p.title + ' · case study soon');
      setHyper(false);
    }, 1200);
  };

  return (
    <>
      <header className="topbar">
        <div className="brand-name">SPANDAN PATIL</div>
        <div className="topbar-meta">
          <div><span className="key">LOCATION</span><span className="val">NEW YORK, NY</span></div>
          <div><span className="key">LOCAL TIME</span><span className="val signal">{clock}</span></div>
        </div>
      </header>

      <main>
        {page === 'work'  && <WorkPage onOpen={openProject}/>}
        {page === 'about' && <AboutPage/>}
        {page === 'dsrpt' && <DSRPTPage/>}
      </main>

      <Hyperspace active={hyper}/>

      <nav className="pill-nav">
        <button className={page==='work'?'active':''} onClick={()=> setPage('work')}>Work</button>
        <button className={page==='about'?'active':''} onClick={()=> setPage('about')}>About</button>
        <button className={page==='dsrpt'?'active':''} onClick={()=> setPage('dsrpt')}>DSRPT</button>
      </nav>

      <div className={'toast ' + (toast?'show':'')}>{toast}</div>

      <TweaksPanel title="Tweaks">
        <TweakSection label="Atmosphere"/>
        <TweakRadio label="Starfield" value={t.stars} options={['subtle','medium','heavy']} onChange={(v)=>setTweak('stars', v)}/>
        <TweakToggle label="Curved grid" value={t.curve} onChange={(v)=>setTweak('curve', v)}/>
        <TweakSection label="Brand"/>
        <TweakColor label="Signal accent" value={t.accent} onChange={(v)=>setTweak('accent', v)}/>
      </TweaksPanel>
    </>
  );
}

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(<App/>);
